    if (network.name === 'mainnet' || network.name === 'polygon') {
      const confirmed = process.env.AUDIT_CONFIRMED;
      if (confirmed !== 'true') {
        throw new Error('Mainnet deploy blocked. Set AUDIT_CONFIRMED=true only after audit report is published.');
