File: smart-contracts/contracts/AegisTradeEscrow.sol

When initiateDispute() is called the contract sets status to DISPUTED then
does nothing. Funds can be permanently locked with no resolution path.

Implementation:
- Add disputeDeadline to the Escrow struct: uint256 disputeDeadline;
- In initiateDispute():

    e.disputeDeadline = block.timestamp + 14 days;
    emit DisputeInitiated(escrowId, msg.sender, e.disputeDeadline);

- Add a resolveDispute() function:

    function resolveDispute(uint256 escrowId, bool releaseToSeller)
      external onlyRole(ARBITRATOR_ROLE) {
      Escrow storage e = escrows[escrowId];
      require(e.status == EscrowStatus.DISPUTED, "Not in disputed state");
      require(block.timestamp <= e.disputeDeadline, "Arbitration deadline passed");
      e.status = releaseToSeller ? EscrowStatus.RELEASED : EscrowStatus.REFUNDED;
      _transferFunds(escrowId, releaseToSeller);
      emit DisputeResolved(escrowId, releaseToSeller, msg.sender);
    }

- Add a claimStaleDispute() function callable by either party after the
  deadline passes, which returns funds to the buyer:

    function claimStaleDispute(uint256 escrowId) external {
      Escrow storage e = escrows[escrowId];
      require(e.status == EscrowStatus.DISPUTED, "Not in disputed state");
      require(block.timestamp > e.disputeDeadline, "Deadline not yet passed");
      e.status = EscrowStatus.REFUNDED;
      _transferFunds(escrowId, false);
      emit StaleDisputeClaimed(escrowId, msg.sender);
    }

Files: all service index.js files

Most endpoints accept raw req.body with no type, range, or required field
validation. Malformed requests cause runtime crashes.

Implementation:
- Install zod in every Node.js service
- Create a validateBody middleware factory:

    const { z } = require('zod');

    function validateBody(schema) {
      return (req, res, next) => {
        const result = schema.safeParse(req.body);
        if (!result.success) {
          return res.status(400).json({
            error: 'Validation failed',
            details: result.error.flatten()
          });
        }
        req.body = result.data;
        next();
      };
    }

- Apply schema validation to every POST, PUT, and PATCH endpoint
- Define schemas for: transfers, KYB submissions, wallet provisioning,
  compliance screening, trade escrow creation, fiat ramp requests

File: All service environment config checks

MOCK_FIREBLOCKS defaults to production mode (undefined = off).
MOCK_OPENPAYD defaults to mock mode (undefined = on).
A misconfigured deployment could run fiat ramps in mock mode while Fireblocks
operates against real funds.

Implementation:
- Change every mock check in every service to === 'true':

    const MOCK_OPENPAYD = process.env.MOCK_OPENPAYD === 'true';
    const MOCK_FIREBLOCKS = process.env.MOCK_FIREBLOCKS === 'true';
    const MOCK_AML = process.env.MOCK_AML === 'true';
    const MOCK_KAFKA = process.env.MOCK_KAFKA === 'true';

- This means undefined = production mode for all integrations consistently
- Add a startup log in every service that prints the resolved mode:

    console.log('[CONFIG] Integration modes:', {
      fireblocks: MOCK_FIREBLOCKS ? 'MOCK' : 'PRODUCTION',
      openpayd: MOCK_OPENPAYD ? 'MOCK' : 'PRODUCTION',
      aml: MOCK_AML ? 'MOCK' : 'PRODUCTION'
    });

File: services/compliance-engine/src/index.js

The evalCond function traverses user-controlled field paths with reduce.
If a rule contains __proto__.admin or constructor.prototype.role, the
Node.js object prototype can be silently polluted.

Implementation:
- Define an explicit whitelist of permitted field paths:

    const ALLOWED_RULE_FIELDS = new Set([
      'amount', 'currency', 'transactionType',
      'sender.country', 'sender.riskScore', 'sender.companyId',
      'receiver.country', 'receiver.riskScore', 'receiver.companyId'
    ]);

- Before evaluating any rule, check: if (!ALLOWED_RULE_FIELDS.has(c.field)) throw
- Before passing tx to evalCond, validate it with Ajv:

    const Ajv = require('ajv');
    const ajv = new Ajv({ removeAdditional: true, coerceTypes: false });

    const txSchema = {
      type: 'object',
      properties: {
        amount: { type: 'number' },
        currency: { type: 'string', enum: ['USDC', 'USDT', 'AE_COIN', 'USDC_SOL'] },
        transactionType: { type: 'string' },
        sender: {
          type: 'object',
          properties: {
            country: { type: 'string' },
            riskScore: { type: 'number' },
            companyId: { type: 'string' }
          },
          additionalProperties: false
        },
        receiver: {
          type: 'object',
          properties: {
            country: { type: 'string' },
            riskScore: { type: 'number' },
            companyId: { type: 'string' }
          },
          additionalProperties: false
        }
      },
      additionalProperties: false
    };

    ajv.validate(txSchema, tx);
    Object.freeze(tx);

File: services/wallet-service/src/index.js

publishEvent() has a comment "// Kafka producer here" for the production
path and silently returns in development. The transfer.pending_approval
event for the maker-checker workflow is never published, breaking approval
for all transfers above $500,000.

Implementation:
- Initialize a real Kafka producer at service startup:

    const { Kafka } = require('kafkajs');
    const kafka = new Kafka({
      clientId: 'wallet-service',
      brokers: process.env.KAFKA_BROKERS.split(',')
    });
    const producer = kafka.producer({
      idempotent: true,
      maxInFlightRequests: 1
    });

    async function initKafka() {
      await producer.connect();
      console.log('[KAFKA] Producer connected');
    }

- Replace publishEvent() with:

    async function publishEvent(topic, payload) {
      if (process.env.MOCK_KAFKA === 'true') {
        console.log('[KAFKA MOCK] Topic:', topic, JSON.stringify(payload));
        return;
      }
      await producer.send({
        topic,
        messages: [{
          key: payload.transferId || payload.walletId || 'default',
          value: JSON.stringify(payload)
        }]
      });
    }

- Call initKafka() before the Express server starts listening
- Add KAFKA_BROKERS to .env.example: KAFKA_BROKERS=kafka-1:9092,kafka-2:9092,kafka-3:9092


