File: smart-contracts/contracts/AegisBoLNFT.sol

The contract rolls its own ERC1155 implementation missing safeTransferFrom,
safeBatchTransferFrom, and supportsInterface. No external wallet, custodian,
or marketplace can integrate with it.

Implementation:
- Inherit from OpenZeppelin ERC1155 and AccessControl
- Preserve ALL existing custom logic: BillOfLading struct, endorseBoL(),
  lockInEscrow(), redeemBoL(), the endorsement chain, IPFS hash storage,
  and all trade reference fields
- The struct and custom functions layer on top of the OZ base:

    import "@openzeppelin/contracts/token/ERC1155/ERC1155.sol";
    import "@openzeppelin/contracts/access/AccessControl.sol";

    contract AegisBoLNFT is ERC1155, AccessControl {

      struct BillOfLading {
        string tradeReference;
        string ipfsDocumentHash;
        string portOfLoading;
        string portOfDischarge;
        address[] endorsementChain;
        bool lockedInEscrow;
        bool redeemed;
      }

      mapping(uint256 => BillOfLading) public bills;

      bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
      bytes32 public constant ESCROW_ROLE = keccak256("ESCROW_ROLE");

      constructor(string memory uri_) ERC1155(uri_) {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
      }

      function mintBoL(
        address to,
        uint256 tokenId,
        BillOfLading calldata data
      ) external onlyRole(MINTER_ROLE) {
        bills[tokenId] = data;
        _mint(to, tokenId, 1, "");
      }

      function endorseBoL(uint256 tokenId, address newHolder) external { ... }
      function lockInEscrow(uint256 tokenId) external onlyRole(ESCROW_ROLE) { ... }
      function redeemBoL(uint256 tokenId) external { ... }

      function supportsInterface(bytes4 interfaceId)
        public view override(ERC1155, AccessControl) returns (bool) {
        return super.supportsInterface(interfaceId);
      }
    }

