File: smart-contracts/contracts/AegisTrancheEscrow.sol

Any tranche can be released in any order. This breaks the fundamental
guarantee of sequential trade condition enforcement.

Implementation:

    function releaseTranche(uint256 escrowId, uint8 trancheIndex) external {
      Tranche storage t = escrows[escrowId].tranches[trancheIndex];

      if (trancheIndex > 0) {
        for (uint8 i = 0; i < trancheIndex; i++) {
          require(
            escrows[escrowId].tranches[i].released,
            "Prior tranche must be released first"
          );
        }
      }

      require(!t.released, "Tranche already released");
      t.released = true;
      _transferTrancheFunds(escrowId, trancheIndex);
      emit TrancheReleased(escrowId, trancheIndex, t.amount);
    }

  Note: the loop bound is i < trancheIndex — this avoids the uint8 underflow
  that would occur with i < t.order - 1 when order is 0.


