File: services/fiat-service/src/index.js

POST /webhook/openpayd accepts any request and marks payments as COMPLETED
based on the paymentId in the body alone.

Implementation:
- Use express.raw() to preserve the raw body for HMAC:

    app.post('/webhook/openpayd',
      express.raw({ type: 'application/json' }),
      (req, res) => {
        const sig = req.headers['x-openpayd-signature'];
        if (!sig) return res.status(401).json({ error: 'Missing signature' });

        const expected = require('crypto')
          .createHmac('sha256', process.env.OPENPAYD_WEBHOOK_SECRET)
          .update(req.body)
          .digest('hex');

        if (!require('crypto').timingSafeEqual(Buffer.from(sig), Buffer.from(expected))) {
          return res.status(401).json({ error: 'Invalid signature' });
        }

        const event = JSON.parse(req.body);
        // process event
      }
    );

- Add OPENPAYD_WEBHOOK_SECRET to .env.example as required

File: services/billing-service/src/index.js

No Stripe webhook endpoint exists. Payment failures, disputes, and
subscription cancellations are never handled.

Implementation:
- Add:

    app.post('/webhook/stripe',
      express.raw({ type: 'application/json' }),
      async (req, res) => {
        let event;
        try {
          event = stripe.webhooks.constructEvent(
            req.body,
            req.headers['stripe-signature'],
            process.env.STRIPE_WEBHOOK_SECRET
          );
        } catch (err) {
          return res.status(400).send('Webhook Error: ' + err.message);
        }

        switch (event.type) {
          case 'invoice.payment_failed':
            await db.query(
              "UPDATE companies SET subscription_status = 'past_due' WHERE stripe_customer_id = $1",
              [event.data.object.customer]
            );
            await notifyOpsTeam('payment_failed', event.data.object);
            break;

          case 'customer.subscription.deleted':
            await db.query(
              "UPDATE companies SET subscription_status = 'cancelled' WHERE stripe_customer_id = $1",
              [event.data.object.customer]
            );
            await revokeCompanyAccess(event.data.object.customer);
            break;

          case 'charge.dispute.created':
            await notifyOpsTeam('dispute_created', event.data.object);
            break;
        }

        res.json({ received: true });
      }
    );

- Add STRIPE_WEBHOOK_SECRET to .env.example
- Register the webhook URL in the Stripe dashboard

File: services/trade-service/src/index.js (or trade-extensions)

POST /bol/:tokenId/transfer has no check that the requesting company
owns the token. Any authenticated user can steal any Bill of Lading.

Implementation:
- Before the UPDATE, verify ownership:

    const current = await db.query(
      'SELECT owner_company FROM bol_nfts WHERE token_id = $1',
      [req.params.tokenId]
    );

    if (!current.rows.length) {
      return res.status(404).json({ error: 'BoL token not found' });
    }

    if (current.rows[0].owner_company !== req.user.companyId) {
      return res.status(403).json({ error: 'You do not own this BoL token' });
    }

    await db.query(
      'UPDATE bol_nfts SET owner_company = $1 WHERE token_id = $2',
      [req.body.transferToCompany, req.params.tokenId]
    );

File: services/trade-service/src/index.js

POST /lc/:id/draw fetches the LC with WHERE id = $1 only. Any user who
knows an LC's ID can draw against it.

Implementation:
- Add a company filter to the fetch:

    const lc = await db.query(
      'SELECT * FROM letters_of_credit WHERE id = $1 AND company_id = $2',
      [req.params.id, req.user.companyId]
    );

    if (!lc.rows.length) {
      return res.status(404).json({ error: 'Letter of Credit not found' });
